// Cloudflare Worker with SendGrid and Stripe integration

const SENDGRID_API_KEY = 'YOUR_SENDGRID_API_KEY';
const STRIPE_SECRET_KEY = 'YOUR_STRIPE_SECRET_KEY';
const ALLOWED_ORIGINS = ['https://yourdomain.com', 'https://www.yourdomain.com'];
const WORKER_AUTH_TOKEN = 'YOUR_WORKER_AUTH_TOKEN';

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
  if (request.method === 'OPTIONS') {
    return handleCORS(request);
  }

  const url = new URL(request.url);
  const path = url.pathname;

  try {
    if (!authenticateRequest(request)) {
      return jsonResponse({ error: 'Unauthorized' }, 401);
    }

    if (path === '/send-email' && request.method === 'POST') {
      return await handleSendEmail(request);
    }

    if (path === '/create-payment-intent' && request.method === 'POST') {
      return await handleCreatePaymentIntent(request);
    }

    if (path === '/create-customer' && request.method === 'POST') {
      return await handleCreateCustomer(request);
    }

    if (path === '/webhook/stripe' && request.method === 'POST') {
      return await handleStripeWebhook(request);
    }

    if (path === '/charge' && request.method === 'POST') {
      return await handleCharge(request);
    }

    if (path === '/refund' && request.method === 'POST') {
      return await handleRefund(request);
    }

    return jsonResponse({ error: 'Not found' }, 404);
  } catch (error) {
    return handleError(error);
  }
}

function authenticateRequest(request) {
  const authHeader = request.headers.get('Authorization');
  if (!authHeader) return false;

  const token = authHeader.replace('Bearer ', '');
  return token === WORKER_AUTH_TOKEN;
}

function handleCORS(request) {
  const origin = request.headers.get('Origin');
  const headers = {
    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    'Access-Control-Max-Age': '86400',
  };

  if (origin && ALLOWED_ORIGINS.includes(origin)) {
    headers['Access-Control-Allow-Origin'] = origin;
  }

  return new Response(null, { headers });
}

function addCORSHeaders(response, request) {
  const origin = request.headers.get('Origin');
  if (origin && ALLOWED_ORIGINS.includes(origin)) {
    response.headers.set('Access-Control-Allow-Origin', origin);
  }
  response.headers.set('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  response.headers.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  return response;
}

async function handleSendEmail(request) {
  try {
    const body = await request.json();
    const { to, from, subject, text, html } = body;

    if (!to || !from || !subject || (!text && !html)) {
      return jsonResponse({ error: 'Missing required fields: to, from, subject, and text or html' }, 400);
    }

    const emailData = {
      personalizations: [{ to: [{ email: to }] }],
      from: { email: from },
      subject: subject,
    };

    if (html) {
      emailData.content = [{ type: 'text/html', value: html }];
    } else {
      emailData.content = [{ type: 'text/plain', value: text }];
    }

    const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${SENDGRID_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(emailData),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`SendGrid API error: ${response.status} - ${errorText}`);
    }

    return jsonResponse({ success: true, message: 'Email sent successfully' }, 200, request);
  } catch (error) {
    throw new Error(`Email sending failed: ${error.message}`);
  }
}

async function handleCreatePaymentIntent(request) {
  try {
    const body = await request.json();
    const { amount, currency = 'usd', metadata = {} } = body;

    if (!amount || amount <= 0) {
      return jsonResponse({ error: 'Invalid amount' }, 400);
    }

    const params = new URLSearchParams();
    params.append('amount', Math.round(amount));
    params.append('currency', currency);
    
    Object.keys(metadata).forEach(key => {
      params.append(`metadata[${key}]`, metadata[key]);
    });

    const response = await fetch('https://api.stripe.com/v1/payment_intents', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: params.toString(),
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(`Stripe API error: ${data.error?.message || response.statusText}`);
    }

    return jsonResponse({
      success: true,
      clientSecret: data.client_secret,
      paymentIntentId: data.id,
    }, 200, request);
  } catch (error) {
    throw new Error(`Payment intent creation failed: ${error.message}`);
  }
}

async function handleCreateCustomer(request) {
  try {
    const body = await request.json();
    const { email, name, metadata = {} } = body;

    if (!email) {
      return jsonResponse({ error: 'Email is required' }, 400);
    }

    const params = new URLSearchParams();
    params.append('email', email);
    if (name) params.append('name', name);
    
    Object.keys(metadata).forEach(key => {
      params.append(`metadata[${key}]`, metadata[key]);
    });

    const response = await fetch('https://api.stripe.com/v1/customers', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: params.toString(),
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(`Stripe API error: ${data.error?.message || response.statusText}`);
    }

    return jsonResponse({
      success: true,
      customerId: data.id,
      customer: data,
    }, 200, request);
  } catch (error) {
    throw new Error(`Customer creation failed: ${error.message}`);
  }
}

async function handleCharge(request) {
  try {
    const body = await request.json();
    const { amount, currency = 'usd', source, description, customer } = body;

    if (!amount || amount <= 0) {
      return jsonResponse({ error: 'Invalid amount' }, 400);
    }

    if (!source && !customer) {
      return jsonResponse({ error: 'Either source or customer is required' }, 400);
    }

    const params = new URLSearchParams();
    params.append('amount', Math.round(amount));
    params.append('currency', currency);
    if (source) params.append('source', source);
    if (customer) params.append('customer', customer);
    if (description) params.append('description', description);

    const response = await fetch('https://api.stripe.com/v1/charges', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: params.toString(),
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(`Stripe API error: ${data.error?.message || response.statusText}`);
    }

    return jsonResponse({
      success: true,
      chargeId: data.id,
      status: data.status,
      charge: data,
    }, 200, request);
  } catch (error) {
    throw new Error(`Charge failed: ${error.message}`);
  }
}

async function handleRefund(request) {
  try {
    const body = await request.json();
    const { chargeId, amount, reason } = body;

    if (!chargeId) {
      return jsonResponse({ error: 'Charge ID is required' }, 400);
    }

    const params = new URLSearchParams();
    params.append('charge', chargeId);
    if (amount) params.append('amount', Math.round(amount));
    if (reason) params.append('reason', reason);

    const response = await fetch('https://api.stripe.com/v1/refunds', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: params.toString(),
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(`Stripe API error: ${data.error?.message || response.statusText}`);
    }

    return jsonResponse({
      success: true,
      refundId: data.id,
      status: data.status,
      refund: data,
    }, 200, request);
  } catch (error) {
    throw new Error(`Refund failed: ${error.message}`);
  }
}

async function handleStripeWebhook(request) {
  try {
    const body = await request.text();
    const signature = request.headers.get('stripe-signature');

    if (!signature) {
      return jsonResponse({ error: 'No signature provided' }, 400);
    }

    const event = JSON.parse(body);

    switch (event.type) {
      case 'payment_intent.succeeded':
        console.log('Payment succeeded:', event.data.object.id);
        break;
      case 'payment_intent.payment_failed':
        console.log('Payment failed:', event.data.object.id);
        break;
      case 'customer.created':
        console.log('Customer created:', event.data.object.id);
        break;
      case 'charge.refunded':
        console.log('Charge refunded:', event.data.object.id);
        break;
      default:
        console.log('Unhandled event type:', event.type);
    }

    return jsonResponse({ received: true }, 200, request);
  } catch (error) {
    throw new Error(`Webhook processing failed: ${error.message}`);
  }
}

function handleError(error) {
  console.error('Error:', error);

  let statusCode = 500;
  let message = 'Internal server error';

  if (error.message.includes('Invalid amount')) {
    statusCode = 400;
    message = error.message;
  } else if (error.message.includes('Unauthorized')) {
    statusCode = 401;
    message = 'Unauthorized';
  } else if (error.message.includes('Not found')) {
    statusCode = 404;
    message = 'Not found';
  } else if (error.message.includes('API error')) {
    statusCode = 502;
    message = error.message;
  }

  return jsonResponse({
    error: message,
    details: error.message,
  }, statusCode);
}

function jsonResponse(data, status = 200, request = null) {
  const response = new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
    },
  });

  if (request) {
    return addCORSHeaders(response, request);
  }

  return response;
}